import java.util.TreeSet;

public class Solution {
    public static long solve(String s, long[] order, long k) {
        int n = s.length();
        long total_substrings = n * (n + 1) / 2;
        TreeSet<Integer> set = new TreeSet<>();
        long invalid = total_substrings;
        for (int t = 0; t < n; t++) {
            int x = (int) order[t];
            Integer prev = set.floor(x);
            Integer next = set.ceil(x);
            int start = (prev == null) ? 0 : prev + 1;
            int end = (next == null) ? n - 1 : next - 1;
            int original_length = end - start + 1;
            long original_contribution = original_length * (original_length + 1) / 2;
            invalid -= original_contribution;
            int left_start = start;
            int left_end = x - 1;
            int left_length = left_end - left_start + 1;
            long left_contribution = left_length * (left_length + 1) / 2;
            int right_start = x + 1;
            int right_end = end;
            int right_length = right_end - right_start + 1;
            long right_contribution = right_length * (right_length + 1) / 2;
            invalid += left_contribution + right_contribution;
            set.add(x);
            long valid = total_substrings - invalid;
            if (valid >= k) {
                return t;
            }
        }
        return -1;
    }
}
